        outlineDefaultAccentMinorGradientActive.overrideBy(outlineOnDarkAccentMinorGradientActive)
        outlineDefaultAccentMinorGradient.overrideBy(outlineOnDarkAccentMinorGradient)
        outlineDefaultTransparentAccentGradientHover.overrideBy(outlineOnDarkTransparentAccentGradientHover)
        outlineDefaultTransparentAccentGradientActive.overrideBy(outlineOnDarkTransparentAccentGradientActive)
        outlineDefaultTransparentAccentGradient.overrideBy(outlineOnDarkTransparentAccentGradient)
        outlineDefaultPromoGradientHover.overrideBy(outlineOnDarkPromoGradientHover)
        outlineDefaultPromoGradientActive.overrideBy(outlineOnDarkPromoGradientActive)
        outlineDefaultPromoGradient.overrideBy(outlineOnDarkPromoGradient)
        outlineDefaultPromoMinorGradientHover.overrideBy(outlineOnDarkPromoMinorGradientHover)
        outlineDefaultPromoMinorGradientActive.overrideBy(outlineOnDarkPromoMinorGradientActive)
        outlineDefaultPromoMinorGradient.overrideBy(outlineOnDarkPromoMinorGradient)
        outlineDefaultAccentGradient.overrideBy(outlineOnDarkAccentGradient)
    }
}

/**
 * Подтема SddsSandboxTheme.OnDark
 */
@Composable
public fun SddsSandboxTheme.OnDark(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalSddsSandboxColors.current
    val overrideColors = currentColors.copyAttrs(OnDarkColorsOverride)
    val currentGradients = LocalSddsSandboxGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnDarkGradientsOverride)
    SddsSandboxTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
